  parts.push({
    type: 'hook',
    hookId: (b.hook_id ?? '') as string,
    hookName: (b.hook_name ?? '') as string,
    hookEvent: (b.hook_event ?? '') as string,
    status: (b.status ?? 'completed') as 'running' | 'completed' | 'error',
